head.script:
scwin.btnFlag = "";
scwin.rowFlag = "";
scwin.pos_groupCode = 0;
scwin.hd_eqCd = "";
scwin.txt_upr = "";
scwin.txt_check = "";
scwin.loUpperLobranCd = "";
scwin.userClsCd = "";

scwin.onpageload = function() {
    scwin.loUpperLobranCd = $c.ses.getLoUpperLobranCd();
    scwin.userClsCd = $c.ses.getUserClsCd();
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    ed_wrkDt.setValue(scwin.vCurDate);
    ed_wrkDt.setFocus();
    scwin.f_switchObjMode(1);
};

scwin.onUdcCompleted = function() {
};

scwin.f_qeryList = async function() {
    if (!(await $c.gus.cfValidate([ed_eqCd, ed_wrkDt]))) {
        return;
    }
    dma_condition.set("eqCd", scwin.hd_eqCd);
    dma_condition.set("wrkDt", ed_wrkDt.getValue());
    await $c.sbm.execute(sbm_searchHeavyEquipWorkResults);
};

scwin.f_save = async function(argFlag) {
    let row = 0;
    let isSupplyOil = false;
    let isSupplyOilOnly = false;

    switch (argFlag) {
        case 1:
            let v_checkYn = false;
            for (let i = 0; i < ds_heavyEquipWorkIndication.getRowCount(); i++) {
                if (ds_heavyEquipWorkIndication.getCellData(i, "chk") == 1) {
                    ds_heavyEquipWorkIndication.setCellData(i, "pchsClntNo", ds_heavyEquipBasisInformation.getCellData(0, "logisHveqRepCopCoNo"));
                    ds_heavyEquipWorkIndication.setCellData(i, "copClntNo", ds_heavyEquipBasisInformation.getCellData(0, "clntNo"));
                    v_checkYn = true;
                    break;
                }
            }

            if (v_checkYn) {
                row = ds_heavyEquipWorkIndication.getRowPosition();
                await $c.sbm.execute(sbm_CreateHeavyEquipResultsData);
                await scwin.f_qeryList();
                ds_heavyEquipWorkIndication.setRowPosition(row);
            } else {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["작업지시"]);
                return;
            }
            break;
        case 2:
            if (ds_heavyEquipWorkResults.getRowCount() == 0) return;
            if (!ds_heavyEquipWorkResults.isUpdated()
             && (!ds_oilingResults.isUpdated() || (ds_oilingResults.getCellData(0, "oilStatCd") == "" && ds_oilingResults.getRowStatus(0) == "C"))
             && !ds_heavyEquipBasisInformation.isUpdated()
             && !ds_heavyEquipNonOperationHour.isUpdated()) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["중기실적"]);
                return;
            }

            if (ds_oilingResults.getRowStatus(0) == "C" && (ds_oilingResults.getCellData(0, "oilStatCd") != "" || ds_oilingResults.getCellData(0, "oilingVol") > 0))
                isSupplyOil = true;

            for (let i = 0; i < ds_heavyEquipWorkResults.getRowCount(); i++) {
                if (ds_heavyEquipWorkResults.getRowStatus(i) != "R") {

                    if (ds_heavyEquipWorkResults.getRowStatus(i) == "C") {
                        for (let j = 0; j < ds_heavyEquipWorkResults.getRowCount(); j++) {
                            if (ds_heavyEquipWorkResults.getCellData(i, "wrkIndictNo") == ds_heavyEquipWorkResults.getCellData(j, "wrkIndictNo")
                             && ds_heavyEquipWorkResults.getCellData(i, "eqCd") == ds_heavyEquipWorkResults.getCellData(j, "eqCd")
                             && ds_heavyEquipWorkResults.getCellData(i, "impExpClsCd") == ds_heavyEquipWorkResults.getCellData(j, "impExpClsCd")
                             && i != j) {
                                await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터는 중복 데이터이므로 입력하실 수 없습니다.");
                                ds_heavyEquipWorkResults.setRowPosition(i);
                                return;
                            }
                        }
                    }

                    if (ds_heavyEquipWorkResults.getCellData(i, "wrkIndictNo").trim() == "") {
                        await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업지시번호는 필수입력항목 입니다.");
                        ds_heavyEquipWorkResults.setRowPosition(i);
                        ed_wrkIndictNo.setFocus();
                        return;
                    }

                    if (ds_heavyEquipWorkResults.getCellData(i, "wrkIndictClsCd") == "P") {
                        if (ds_heavyEquipWorkResults.getCellData(i, "impExpClsCd") == "Y") {
                            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 수출입구분은 필수입력항목 입니다.");
                            ds_heavyEquipWorkResults.setRowPosition(i);
                            lc_impExpClsCd.setFocus();
                            return;
                        }
                    }

                    if (ds_heavyEquipWorkResults.getCellData(i, "wrkStpCd").trim() == "") {
                        await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업단계는 필수입력항목 입니다.");
                        ds_heavyEquipWorkResults.setRowPosition(i);
                        lc_wrkStpCd.setFocus();
                        return;
                    }

                    if (ds_heavyEquipWorkResults.getRowStatus(i) != "U") {
                        if (ds_heavyEquipWorkResults.getCellData(i, "wrkStDt").trim() == "") {
                            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업시작일자는 필수입력항목 입니다.");
                            ds_heavyEquipWorkResults.setRowPosition(i);
                            ica_wrkStDt.setFocus();
                            return;
                        }
                        if (ds_heavyEquipWorkResults.getCellData(i, "wrkStHh").trim() == "") {
                            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업시작시간는 필수입력항목 입니다.");
                            ds_heavyEquipWorkResults.setRowPosition(i);
                            ed_wrkStHh.setFocus();
                            return;
                        }
                        if (ds_heavyEquipWorkResults.getCellData(i, "wrkEndDt").trim() == "") {
                            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업종료일자는 필수입력항목 입니다.");
                            ds_heavyEquipWorkResults.setRowPosition(i);
                            ica_wrkEndDt.setFocus();
                            return;
                        }
                        if (ds_heavyEquipWorkResults.getCellData(i, "wrkEndHh").trim() == "") {
                            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업종료시간는 필수입력항목 입니다.");
                            ds_heavyEquipWorkResults.setRowPosition(i);
                            ed_wrkEndHh.setFocus();
                            return;
                        }

                        if (!(await scwin.f_validateWrkTime(i))) return false;

                        for (let j = 0; j < ds_heavyEquipWorkResults.getRowCount(); j++) {
                            if (ds_heavyEquipWorkResults.getRowStatus(j) != "U" && j != i) {
                                if (!((ds_heavyEquipWorkResults.getCellData(j, "wrkStDt").trim() > ds_heavyEquipWorkResults.getCellData(i, "wrkEndDt").trim()
                                    || (ds_heavyEquipWorkResults.getCellData(j, "wrkStDt").trim() == ds_heavyEquipWorkResults.getCellData(i, "wrkEndDt").trim()
                                     && ds_heavyEquipWorkResults.getCellData(j, "wrkStHh").trim() >= ds_heavyEquipWorkResults.getCellData(i, "wrkEndHh").trim()))
                                   || (ds_heavyEquipWorkResults.getCellData(j, "wrkEndDt").trim() < ds_heavyEquipWorkResults.getCellData(i, "wrkStDt").trim()
                                    || (ds_heavyEquipWorkResults.getCellData(j, "wrkEndDt").trim() == ds_heavyEquipWorkResults.getCellData(i, "wrkStDt").trim()
                                     && ds_heavyEquipWorkResults.getCellData(j, "wrkEndHh").trim() <= ds_heavyEquipWorkResults.getCellData(i, "wrkStHh").trim())))) {
                                    await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적의 작업시간이 " + (j + 1) + "번째 작업실적의 작업시간과 중복됩니다.");
                                    ds_heavyEquipWorkResults.setRowPosition(i);
                                    ica_wrkStDt.setFocus();
                                    return;
                                }
                            }
                        }

                        if (isSupplyOil && ds_oilingResults.getCellData(0, "oilStatCd") == "") {
                            await $c.gus.cfAlertMsg("주유 실적 등록시  주유소는  필수입력항목 입니다.");
                            return;
                        } else if (isSupplyOil && ds_oilingResults.getCellData(0, "oilingVol") == 0) {
                            await $c.gus.cfAlertMsg("주유 실적 등록시  주유량은 0보다 커야 합니다.");
                            return;
                        }

                        if (isSupplyOil &&
                            ds_heavyEquipWorkResults.getCellData(i, "pchsPcost") == 0 &&
                            ds_heavyEquipWorkResults.getCellData(i, "ctrlPchsPcost") == 0 &&
                            ds_heavyEquipWorkResults.getCellData(i, "tformEqPchsPcost") == 0) {
                            isSupplyOilOnly = true;
                        } else {
                            isSupplyOilOnly = false;
                        }

                        if (ds_heavyEquipBasisInformation.getCellData(0, "posnClsCd") != 'J') {
                            if (!isSupplyOilOnly && ds_heavyEquipWorkResults.getCellData(i, "pchsClntNo") == "") {
                                await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 매입거래처는 필수입력항목 입니다.");
                                ds_heavyEquipWorkResults.setRowPosition(i);
                                ed_pchsClntNo.setFocus();
                                return;
                            }

                            if (!isSupplyOilOnly && ds_heavyEquipWorkResults.getCellData(i, "copCoClntNo") == "") {
                                await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 협력업체는 필수입력항목 입니다.");
                                ds_heavyEquipWorkResults.setRowPosition(i);
                                ed_copCoClntNo.setFocus();
                                return;
                            }
                        }

                        if (ds_heavyEquipWorkResults.getCellData(i, "pchsDeptCd") == "") {
                            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 매입부서는 필수입력항목 입니다.");
                            ds_heavyEquipWorkResults.setRowPosition(i);
                            ed_pchsDeptCd.setFocus();
                            return;
                        }

                        if (!isSupplyOilOnly && ds_heavyEquipWorkResults.getCellData(i, "pchsPcost") == 0) {
                            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 매입원가는 필수입력항목 입니다.");
                            ds_heavyEquipWorkResults.setRowPosition(i);
                            but_CalcPchsPcost.setFocus();
                            return;
                        }

                        if (!isSupplyOilOnly
                            && ds_heavyEquipWorkResults.getCellData(i, "ctrlPchsPcost") != 0
                            && ds_heavyEquipWorkResults.getCellData(i, "ctrlPchsPcostRsn") == "") {
                            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 조정사유는 필수입력항목 입니다.");
                            lc_ctrlPchsPcostRsn.setFocus();
                            return;
                        }
                    }
                }
            }

            for (let i = 0; i < ds_heavyEquipNonOperationHour.getRowCount(); i++) {
                if (ds_heavyEquipNonOperationHour.getCellData(i, "nonoprtHhCnt") == 0
                 && ds_heavyEquipNonOperationHour.getCellData(i, "nonoprtMintCnt") == 0) {
                    await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["비가동시간"]);
                    ds_heavyEquipNonOperationHour.setRowPosition(i);
                    gr_heavyEquipNonOperationHour.setFocusedCell(i, "nonoprtHhCnt");
                    return;
                }
                if (ds_heavyEquipNonOperationHour.getCellData(i, "nonoprtRsnCd") == "") {
                    await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["비가동사유"]);
                    ds_heavyEquipNonOperationHour.setRowPosition(i);
                    gr_heavyEquipNonOperationHour.setFocusedCell(i, "nonoprtRsnCd");
                    return;
                }
            }

            let chk = await $c.win.confirm("저장하시겠습니까?");
            if (chk) {
                scwin.pos_groupCode = ds_heavyEquipWorkResults.getRowPosition();
                row = ds_heavyEquipWorkIndication.getRowPosition();
                ds_heavyEquipBasisInformation.setRowStatus(ds_heavyEquipBasisInformation.getRowPosition(), "C");
                ds_heavyEquipWorkIndication.setRowStatus(ds_heavyEquipWorkIndication.getRowPosition(), "C");

                await $c.sbm.execute(sbm_save);
                ds_heavyEquipWorkResults.setRowPosition(scwin.pos_groupCode);
                ds_heavyEquipWorkIndication.setRowPosition(row);
            }
            break;
    }
};

scwin.f_OnWrkIndictClsCdChanged = function() {
    let curRow = ds_heavyEquipWorkResults.getRowPosition();
    if (curRow < 0) return;
    if (ds_heavyEquipWorkResults.getCellData(curRow, "wrkIndictClsCd") == "P") {
        sbm_wrkStpCd.action = "/ds.lo.comninfomgnt.RetrieveWorkStepListCMD.do?upperWrkStpCd=01&lvl=3&wrkPlanTrgtYn=1";
        $c.gus.cfEnableBtnOnly([lc_impExpClsCd]);
        lc_impExpClsCd.mandatory = "true";
    } else {
        ds_heavyEquipWorkResults.setCellData(curRow, "impExpClsCd", "Y");
        sbm_wrkStpCd.action = "/ds.lo.comninfomgnt.RetrieveWorkStepListCMD.do?upperWrkStpCd=03&lvl=3&wrkPlanTrgtYn=1";
        $c.gus.cfDisableObjects([lc_impExpClsCd]);
        lc_impExpClsCd.mandatory = "false";
    }
    $c.gus.cfRefreshMandSign();
    $c.sbm.execute(sbm_wrkStpCd);

    sbm_nesEqNrmCd.action = "/cm.zz.RetrieveComboCMD.do?sysCd=DsCommonEBC&queryId=retriveNesEqNrmList&param1=" + ds_heavyEquipBasisInformation.getCellData(0, "hveqKndCd");
    $c.sbm.execute(sbm_nesEqNrmCd);
};

scwin.f_validateWrkTime = async function(i) {
    let wrkStDt = ds_heavyEquipWorkResults.getCellData(i, "wrkStDt").trim();
    let wrkStHh = ds_heavyEquipWorkResults.getCellData(i, "wrkStHh").trim();
    let wrkEndDt = ds_heavyEquipWorkResults.getCellData(i, "wrkEndDt").trim();
    let wrkEndHh = ds_heavyEquipWorkResults.getCellData(i, "wrkEndHh").trim();
    let shiftClsCd = ds_heavyEquipWorkResults.getCellData(i, "shiftClsCd");
    let curWrkDt = ed_wrkDt.getValue();
    let nextDay = $c.date.addDate(curWrkDt, 1);

    if (shiftClsCd == 'D') {
        if (wrkStDt.length > 0 && wrkStDt != curWrkDt) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_030 + "작업일자와 같은날만 가능합니다", ["주간의 작업시작일자"]);
            ica_wrkStDt.setFocus();
            return false;
        }
    } else {
        if (wrkStDt.length > 0 && (wrkStDt < curWrkDt || wrkStDt > nextDay)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_030 + "작업일자 하루이후까지만 가능합니다", ["야간/심야의 작업시작일자"]);
            ica_wrkStDt.setFocus();
            return false;
        }
        if (wrkEndDt == nextDay) {
            if (wrkEndHh > '0800') {
                await $c.gus.cfAlertMsg("야간/심야의 작업종료시간은 08시 이전이어야 합니다.");
                ed_wrkEndHh.setFocus();
                return false;
            }
        }
    }

    if (wrkStDt.length == 0 || wrkEndDt.length == 0) return true;

    if (wrkStDt.length != 8 || wrkEndDt.length != 8 || !$c.gus.cfIsAfterDate(wrkStDt, wrkEndDt, false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ica_wrkStDt.setFocus();
        return false;
    }

    if (wrkStHh.length == 0) return true;
    if (wrkStHh.length != 4) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["시간형식"]);
        ed_wrkStHh.setFocus();
        return false;
    }

    if (wrkEndDt.length > 0 && (wrkEndDt < curWrkDt || wrkEndDt > nextDay)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_030 + "작업일자 하루이후까지만 가능합니다", ["종료일자"]);
        ica_wrkEndDt.setFocus();
        return false;
    }
    if (wrkStDt.length == 0 || wrkEndDt.length == 0) return true;

    if (wrkStDt.length != 8 || wrkEndDt.length != 8 || !$c.gus.cfIsAfterDate(wrkStDt, wrkEndDt, false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ica_wrkEndDt.setFocus();
        return false;
    }
    if (wrkEndHh.length == 0) return true;
    if (wrkEndHh.length != 4) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["시간형식"]);
        ed_wrkEndHh.setFocus();
        return false;
    }

    if (wrkStHh.substr(0, 2) > "23") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_021, ["작업시간"]);
        ed_wrkStHh.setFocus();
        return false;
    }
    if (wrkStHh.substr(2, 2) > "59") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]);
        ed_wrkStHh.setFocus();
        return false;
    }

    if (wrkEndHh.substr(0, 2) > "24") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]);
        ed_wrkEndHh.setFocus();
        return false;
    }
    if (wrkEndHh.substr(0, 2) == "00" && wrkEndHh.substr(2, 2) == "00") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]);
        ed_wrkEndHh.setFocus();
        return false;
    }
    if (wrkEndHh.substr(0, 2) == "24" && wrkEndHh.substr(2, 2) > "00") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]);
        ed_wrkEndHh.setFocus();
        return false;
    }
    if (wrkEndHh.substr(2, 2) > "59") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]);
        ed_wrkEndHh.setFocus();
        return false;
    }

    if (wrkStDt == wrkEndDt) {
        if (wrkStHh >= wrkEndHh) {
            await $c.gus.cfAlertMsg("시작시간을 종료시간보다 작게 입력하여 주십시오.");
            ed_wrkStHh.setFocus();
            return false;
        }
    }
    return true;
};

scwin.f_CalcWrkTime = function() {
    let stDt = ica_wrkStDt.getValue().trim();
    let stHh = ed_wrkStHh.getValue().trim();
    let endDt = ica_wrkEndDt.getValue().trim();
    let endHh = ed_wrkEndHh.getValue().trim();

    if (stDt.length != 8) return;
    if (stHh.length != 4) return;
    if (endDt.length != 8) return;
    if (endHh.length != 4) return;

    if (!$c.gus.cfIsAfterDate(stDt, endDt, false)) {
        return;
    } else if (stDt == endDt && stHh > endHh) {
        return;
    }

    let v_daysBetween = $c.date.diffDate(stDt, endDt);

    let v_diff = 0;
    let v_diffHh = 0;
    let v_diffMm = 0;
    let v_StHh = 0;
    let v_StMm = 0;
    let v_EndHh = 0;
    let v_EndMm = 0;

    if (parseInt(stHh.substr(0, 2)) < 10) {
        v_StHh = parseInt(stHh.substr(1, 1));
        v_StMm = parseInt(stHh.substr(2, 2));
    } else {
        v_StHh = parseInt(stHh.substr(0, 2));
        v_StMm = parseInt(stHh.substr(2, 2));
    }

    if (parseInt(endHh.substr(0, 2)) < 10) {
        v_EndHh = parseInt(endHh.substr(1, 1));
        v_EndMm = parseInt(endHh.substr(2, 2));
    } else {
        v_EndHh = parseInt(endHh.substr(0, 2));
        v_EndMm = parseInt(endHh.substr(2, 2));
    }

    if (parseInt(v_daysBetween) > 0) {
        v_daysBetween = parseInt(v_daysBetween) - 1;
        v_diff = parseInt(v_daysBetween) * 24 * 60
                + (24 * 60 - parseInt(v_StHh) * 60 + parseInt(v_StMm))
                + (parseInt(v_EndHh) * 60 + parseInt(v_EndMm));
    } else {
        v_diff = (parseInt(v_EndHh) * 60 + parseInt(v_EndMm))
                - (parseInt(v_StHh) * 60 + parseInt(v_StMm));
    }
    v_diffHh = parseInt(parseInt(v_diff) / 60);
    v_diffMm = parseInt(parseInt(v_diff) % 60);

    ed_totInputHhCnt.setValue(v_diffHh);
    ed_totInputMintCnt.setValue(v_diffMm);

    scwin.f_CalcNonOperationHour();
};

scwin.f_AddRow = async function(gubun) {
    if (gubun == null || gubun == "" || gubun == 0) {
        if (ds_heavyEquipBasisInformation.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_008, ["장비"]);
            return;
        }

        ds_heavyEquipWorkResults.insertRow();

        let curRow = ds_heavyEquipWorkResults.getRowPosition();
        ds_heavyEquipWorkResults.setCellData(curRow, "eqCd", scwin.hd_eqCd);
        ds_heavyEquipWorkResults.setCellData(curRow, "pchsAdjmStdCd", 'H');
        ds_heavyEquipWorkResults.setCellData(curRow, "pchsClntNo", ds_heavyEquipBasisInformation.getCellData(0, "logisHveqRepCopCoNo"));
        ds_heavyEquipWorkResults.setCellData(curRow, "pchsClntNm", ds_heavyEquipBasisInformation.getCellData(0, "logisHveqRepCopCoNm"));
        ds_heavyEquipWorkResults.setCellData(curRow, "copCoClntNo", ds_heavyEquipBasisInformation.getCellData(0, "clntNo"));
        ds_heavyEquipWorkResults.setCellData(curRow, "copCoClntNm", ds_heavyEquipBasisInformation.getCellData(0, "clntNm"));
        ds_heavyEquipWorkResults.setCellData(curRow, "drvStaffNo1", ds_heavyEquipBasisInformation.getCellData(0, "drvEmpNo1"));
        ds_heavyEquipWorkResults.setCellData(curRow, "drvStaffNm1", ds_heavyEquipBasisInformation.getCellData(0, "drvEmpNm1"));

        scwin.f_switchObjMode(8);
    } else {
        let curRow = ds_heavyEquipWorkResults.getRowPosition();
        if (ds_heavyEquipWorkResults.getRowStatus(curRow) == "D") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["삭제된 중기실적", "비가동데이터를 입력"]);
            return;
        }
        if (ds_heavyEquipWorkResults.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_008, ["장비실적"]);
            return;
        }

        let v_wrkIndictNo = ds_heavyEquipWorkResults.getCellData(curRow, "wrkIndictNo");
        let v_eqCd = ds_heavyEquipWorkResults.getCellData(curRow, "eqCd");
        let v_impExpClsCd = ds_heavyEquipWorkResults.getCellData(curRow, "impExpClsCd");

        if (v_wrkIndictNo == "" || v_eqCd == "" || v_impExpClsCd == "") {
            await $c.gus.cfAlertMsg("작업실적관련 기초데이터를 먼저 입력하십시오.");
            return;
        }
        ds_heavyEquipNonOperationHour.insertRow();
        let nRow = ds_heavyEquipNonOperationHour.getRowPosition();
        ds_heavyEquipNonOperationHour.setCellData(nRow, "wrkIndictNo", v_wrkIndictNo);
        ds_heavyEquipNonOperationHour.setCellData(nRow, "eqCd", v_eqCd);
        ds_heavyEquipNonOperationHour.setCellData(nRow, "impExpClsCd", v_impExpClsCd);
    }
};

scwin.f_DeleteRow = async function(gubun) {
    if (gubun == null || gubun == "" || gubun == 0) {
        let curRow = ds_heavyEquipWorkResults.getRowPosition();
        let v_wrkIndictNo = ds_heavyEquipWorkResults.getCellData(curRow, "wrkIndictNo");
        let v_eqCd = ds_heavyEquipWorkResults.getCellData(curRow, "eqCd");
        let v_impExpClsCd = ds_heavyEquipWorkResults.getCellData(curRow, "impExpClsCd");

        for (let i = 0; i < ds_heavyEquipNonOperationHour.getRowCount(); i++) {
            if (ds_heavyEquipNonOperationHour.getCellData(i, "wrkIndictNo") == v_wrkIndictNo
                && ds_heavyEquipNonOperationHour.getCellData(i, "eqCd") == v_eqCd
                && ds_heavyEquipNonOperationHour.getCellData(i, "impExpClsCd") == v_impExpClsCd) {
                ds_heavyEquipNonOperationHour.removeRow(i);
                i--;
            }
        }

        ds_heavyEquipWorkResults.removeRow(curRow);
        scwin.f_switchObjMode(7);
        if (ds_heavyEquipWorkResults.getRowPosition() == 0 && ds_oilingResults.getRowCount() == 1)
            ds_oilingResults.removeRow(0);

    } else {
        let curRow = ds_heavyEquipWorkResults.getRowPosition();
        if (ds_heavyEquipWorkResults.getRowStatus(curRow) == "D") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["삭제된 중기실적", "비가동데이터를 입력"]);
            return;
        }
        let selIdx = ds_heavyEquipNonOperationHour.getRowPosition();
        if (selIdx >= 0) {
            ds_heavyEquipNonOperationHour.removeRow(selIdx);
        }
        scwin.f_CalcNonOperationHour();
    }
};

scwin.f_CancelRow = async function(gubun) {
    if (gubun == null || gubun == "" || gubun == 0) {
        ds_heavyEquipWorkResults.undoAll();
        scwin.f_switchObjMode(7);
        scwin.f_OnWrkIndictClsCdChanged();
        if (ds_heavyEquipWorkResults.getRowPosition() == 0 && ds_oilingResults.getRowCount() == 1)
            ds_oilingResults.undoAll();
    } else {
        let curRow = ds_heavyEquipWorkResults.getRowPosition();
        if (ds_heavyEquipWorkResults.getRowStatus(curRow) == "D") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["삭제된 중기실적", "비가동데이터를 입력"]);
            return;
        }
        ds_heavyEquipNonOperationHour.undoAll();
        scwin.f_CalcNonOperationHour();
    }
};

scwin.f_CalcPchsPcost = async function() {
    if (!(await $c.gus.cfValidate([ed_eqCd, ed_wrkDt]))) return;

    let pchsAdjmStdCdVal = lc_pchsAdjmStdCd.getValue();
    if ("H" == pchsAdjmStdCdVal) {
        if (!(await $c.gus.cfValidate([ed_pchsAdptHhCnt]))) return;
        if (ed_pchsAdptHhCnt.getValue() < 1) {
            await $c.gus.cfAlertMsg("하불임 적용시간을 입력하시오.");
            return;
        }
    } else if ("T" == pchsAdjmStdCdVal) {
        if (!(await $c.gus.cfValidate([ed_wrkWt]))) return;
        if (ed_wrkWt.getValue() < 1) {
            await $c.gus.cfAlertMsg("작업톤수를 입력하시오.");
            return;
        }
    } else if ("" == pchsAdjmStdCdVal) {
        await $c.gus.cfAlertMsg("하불임계산기준을 입력하시오.");
        return;
    }

    if (ds_heavyEquipBasisInformation.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_008, ["중기정보"]);
        return;
    }

    let v_eqNrmCd = ds_heavyEquipBasisInformation.getCellData(0, "hveqNrmCd");
    let curRow = ds_heavyEquipWorkResults.getRowPosition();
    let v_clntNo = ds_heavyEquipWorkResults.getCellData(curRow, "copCoClntNo");
    if (ds_heavyEquipBasisInformation.getCellData(0, "posnClsCd") == 'J') {
        v_clntNo = " ";
    } else {
        if (!(await $c.gus.cfValidate([ed_copCoClntNo]))) {
            return;
        }
    }

    dma_searchPchsPcost.set("lobranCd", ds_heavyEquipBasisInformation.getCellData(0, "lobranCd"));
    dma_searchPchsPcost.set("clntNo", v_clntNo);
    dma_searchPchsPcost.set("eqKndCd", ds_heavyEquipBasisInformation.getCellData(0, "hveqKndCd"));

    let nesVal = lc_nesEqNrmCd.getValue();
    if (nesVal != "") {
        dma_searchPchsPcost.set("eqNrmCd", nesVal);
    } else {
        dma_searchPchsPcost.set("eqNrmCd", v_eqNrmCd);
    }
    dma_searchPchsPcost.set("wrkUnitCd", pchsAdjmStdCdVal);
    dma_searchPchsPcost.set("stDt", ed_wrkDt.getValue());

    ds_searchPchsPcost1.removeAll();
    // TODO: cfCopyDataSetHeader + ExportData/ImportData 로직은 수동 확인 필요
    let rowData = {};
    let colInfos = ds_heavyEquipWorkResults.getColumnIDs();
    for (let ci = 0; ci < colInfos.length; ci++) {
        rowData[colInfos[ci]] = ds_heavyEquipWorkResults.getCellData(curRow, colInfos[ci]);
    }
    ds_searchPchsPcost1.insertRow();
    for (let ci = 0; ci < colInfos.length; ci++) {
        try {
            ds_searchPchsPcost1.setCellData(0, colInfos[ci], rowData[colInfos[ci]]);
        } catch(e) {}
    }

    await $c.sbm.execute(sbm_searchPchsPcost);
};

