scwin.f_CommonPopUp = async function(pSelectID, pCode, pName, pWinCloseTF, pDispCnt, pTitle, pWidth, pHidden, pWhere, pW, pH, pTop, pLeft, pExistTF, pAllSearchTF, pWtitleSearch, pWrkDtTF, pWrkIndictNo, pCvsslMgntNo, pLobranCd, pWrkPlCd) {
    let sW = (pW == null) ? "550px; " : pW + "px; ";
    let sH = (pH == null) ? "460px; " : pH + "px; ";

    let rtnList = [];
    let iDispCnt = null;

    if (pSelectID == null || pSelectID == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["SELECT ID"]);
        return;
    }

    if (pCode.substr(0, 1) == '%' || pName.substr(0, 1) == '%') {
        await $c.gus.cfAlertMsg("검색어 첫번째문자로 @ 는 올 수 없습니다", ["%"]);
        return;
    }

    iDispCnt = (pDispCnt == null) ? "0" : pDispCnt;
    if (parseInt(iDispCnt) > 10) {
        await $c.gus.cfAlertMsg("Display개수는(MAX=@)개 까지 가능 합니다.", ["10"]);
        return;
    }

    switch (pSelectID) {
        case 'retrieveWrkIndictNoList':
            rtnList = await scwin.retrieveWrkIndictNoList(pSelectID, pCode, pName, pWinCloseTF, pDispCnt, pTitle, pWidth, pHidden, pWhere, null, pExistTF, pAllSearchTF, pWtitleSearch, pWrkDtTF, pWrkIndictNo, pCvsslMgntNo, pLobranCd, pWrkPlCd);
            break;
        default:
            await $c.gus.cfAlertMsg(MSG_CM_ERR_047);
            break;
    }
    return rtnList;
};

scwin.f_registrationPopUp = async function() {
    let args = [];
    if (dma_condition.get("eqCd") != scwin.hd_eqCd
     || dma_condition.get("wrkDt") != ed_wrkDt.getValue()
     || ds_heavyEquipWorkResults.getRowCount() == 0) {
        await $c.gus.cfAlertMsg("일괄등록할 실적이 없습니다.");
        return;
    }

    if (ed_pchsPcost.getValue() == 0) {
        await $c.gus.cfAlertMsg("기본실적의 매입원가가 없습니다..");
        return;
    }

    if (!(await $c.gus.cfValidate([ed_pchsDeptCd]))) {
        await $c.gus.cfAlertMsg("기본실적의 매입부서가 없습니다..");
        return;
    }

    let curRow = ds_heavyEquipWorkResults.getRowPosition();
    let indRow = ds_heavyEquipWorkIndication.getRowPosition();
    args[0] = dma_condition.get("eqCd");
    args[1] = dma_condition.get("wrkDt");
    args[2] = ds_heavyEquipWorkResults.getCellData(curRow, "wrkIndictNo");
    args[3] = ds_heavyEquipWorkResults.getCellData(curRow, "impExpClsCd");
    args[4] = ds_heavyEquipWorkResults.getCellData(curRow, "pchsAdjmStdCd");
    args[5] = ds_heavyEquipWorkIndication.getCellData(indRow, "lobranCd");
    args[6] = ds_heavyEquipWorkIndication.getCellData(indRow, "lobranNm");

    await $c.win.openPopup("/ui/ds/op/wrkrslts/stvwrkrslts/op_306_01_25p.xml", {
        width: 900, height: 600, modal: true, data: args
    });

    await scwin.f_qeryList();
};

scwin.retrieveWrkIndictNoList = async function(pSelectID, pCode, pName, pWinCloseTF, pDispCnt, pTitle, pWidth, pHidden, pWhere, sFeatures, pExistTF, pAllSearchTF, pWtitleSearch, pWrkDtTF, pWrkIndictNo, pCvsslMgntNo, pWrkIndictClsCd, pLobranCd, pWrkPlCd) {
    let iDispCnt = (pDispCnt == null) ? "2" : pDispCnt;
    let bWinCloseTF = (pWinCloseTF == null) ? "F" : pWinCloseTF;
    let bExistTF = (pExistTF == null) ? "F" : pExistTF;
    let bAllSearchTF = (pAllSearchTF == null) ? "T" : pAllSearchTF;
    let bWrkDtTF = (pWrkDtTF == null) ? "F" : pWrkDtTF;
    let rtnList = [];
    let arrParm = [];

    arrParm[0] = ["하역작업지시번호 검색", "작업지시구분", "작업일자", pSelectID, bWinCloseTF, iDispCnt, bExistTF, bAllSearchTF, bWrkDtTF];

    if (pWtitleSearch != null) {
        let strArr = pWtitleSearch.split(",");
        if (strArr != null) {
            arrParm[0][0] = strArr[0];
            arrParm[0][1] = strArr[1];
            arrParm[0][2] = strArr[2];
        }
    }

    arrParm[1] = [pCode, pName, pWrkIndictNo, pCvsslMgntNo, pLobranCd, pWrkPlCd];

    let sURL = "/ui/ds/op/wrkplan/stvwrkplan/op_204_02_08p.xml";

    let popupWidth = 550;
    let popupHeight = 460;

    rtnList = await $c.win.openPopup(sURL, {
        width: popupWidth, height: popupHeight, modal: true, data: arrParm
    });

    return rtnList;
};

scwin.f_CalcNonOperationHour = function() {
    if (ds_heavyEquipWorkResults.getRowCount() == 0) return;

    let curRow = ds_heavyEquipWorkResults.getRowPosition();
    let v_wrkIndictNo = ds_heavyEquipWorkResults.getCellData(curRow, "wrkIndictNo");
    let v_eqCd = ds_heavyEquipWorkResults.getCellData(curRow, "eqCd");
    let v_impExpClsCd = ds_heavyEquipWorkResults.getCellData(curRow, "impExpClsCd");
    let v_totInputHhCnt = 0;
    let v_totInputMintCnt = 0;
    let v_NonOperationHh = 0;
    let v_NonOperationMm = 0;
    let v_diff = 0;
    let v_diffHh = 0;
    let v_diffMm = 0;

    if (ed_totInputHhCnt.getValue().trim().length != 0) v_totInputHhCnt = ed_totInputHhCnt.getValue();
    if (ed_totInputMintCnt.getValue().trim().length != 0) v_totInputMintCnt = ed_totInputMintCnt.getValue();

    if (ds_heavyEquipNonOperationHour.getRowCount() != 0) {
        for (let i = 0; i < ds_heavyEquipNonOperationHour.getRowCount(); i++) {
            if (ds_heavyEquipNonOperationHour.getCellData(i, "wrkIndictNo") == v_wrkIndictNo
             && ds_heavyEquipNonOperationHour.getCellData(i, "eqCd") == v_eqCd
             && ds_heavyEquipNonOperationHour.getCellData(i, "impExpClsCd") == v_impExpClsCd
             && ds_heavyEquipNonOperationHour.getRowStatus(i) != "D") {
                if (ds_heavyEquipNonOperationHour.getCellData(i, "nonoprtHhCnt") != "")
                    v_NonOperationHh += parseInt(ds_heavyEquipNonOperationHour.getCellData(i, "nonoprtHhCnt"));
                if (ds_heavyEquipNonOperationHour.getCellData(i, "nonoprtMintCnt") != "")
                    v_NonOperationMm += parseInt(ds_heavyEquipNonOperationHour.getCellData(i, "nonoprtMintCnt"));
            }
        }
        v_diff = (parseInt(v_totInputHhCnt) * 60 + parseInt(v_totInputMintCnt)) - (parseInt(v_NonOperationHh) * 60 + parseInt(v_NonOperationMm));
    } else {
        v_diff = (parseInt(v_totInputHhCnt) * 60 + parseInt(v_totInputMintCnt));
    }

    if (cb_mealYn.getValue() != "" && cb_mealYn.getValue() != null) {
        v_diff = parseInt(v_diff) - 60;
    }

    v_diffHh = parseInt(parseInt(v_diff) / 60);
    v_diffMm = parseInt(parseInt(v_diff) % 60);

    ed_realOprtHhCnt.setValue(v_diffHh);
    ed_realOprtMintCnt.setValue(v_diffMm);
};

scwin.f_chkOpenCommonPopupText = function(inObj, codeObj, disGubun) {
    if (inObj.getValue().trim() == "" || inObj.getReadOnly()) return;
    codeObj.setValue("");
    scwin.f_openCommonPopUp(disGubun);
};

scwin.f_chkOpenCommonPopupEmedit = function(inObj, chkObjVal, txtObj, disGubun) {
    let objValue = inObj.getValue().replace(/^\s*/, '');
    if (txtObj != null) {
        txtObj.setValue("");
    }

    if (objValue == "" || objValue == null) {
        inObj.setValue("");
        if (chkObjVal != null) chkObjVal = "";
        return;
    }

    if (inObj.getReadOnly() || inObj.getDisabled()) return;

    scwin.f_openCommonPopUp(disGubun);
};

scwin.f_switchObjMode = function(gubun) {
    switch (gubun) {
        case 1:
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtn([btn_InitDataCreate, btn_Save]);
            $c.gus.cfDisableObjects([btn_wrkIndictNo, ed_prtgCost, ed_pchsDeptCd, ed_pchsPcost]);
            break;

        case 2:
            break;

        case 3:
            break;

        case 4:
            scwin.f_switchObjMode(1);
            $c.gus.cfEnableKeyData();
            $c.gus.cfDisableKey();
            $c.gus.cfEnableBtnOnly([btn_InitDataCreate, btn_Save]);
            $c.gus.cfEnableObjects([ed_prtgCost, ed_pchsDeptCd]);

            let curRow4 = ds_heavyEquipWorkResults.getRowPosition();
            if (curRow4 >= 0 && ds_heavyEquipWorkResults.getRowStatus(curRow4) == "C") {
                $c.gus.cfEnableObjects([btn_wrkIndictNo, lc_impExpClsCd]);
            }

            if (ds_heavyEquipBasisInformation.getRowCount() > 0) {
                let pchsAdjmVal = lc_pchsAdjmStdCd.getValue();
                if (ds_heavyEquipBasisInformation.getCellData(0, "posnClsCd") == 'J') {
                    $c.gus.cfEnableBtnOnly([but_CalcPchsPcost]);
                    ed_pchsPcost.mandatory = "true";
                    lc_pchsAdjmStdCd.mandatory = "true";
                    ed_copCoClntNo.mandatory = "false";
                    ed_pchsClntNo.mandatory = "false";
                    if ("H" == pchsAdjmVal) {
                        ed_pchsAdptHhCnt.mandatory = "true";
                        ed_wrkWt.mandatory = "false";
                    } else if ("T" == pchsAdjmVal) {
                        ed_pchsAdptHhCnt.mandatory = "false";
                        ed_wrkWt.mandatory = "true";
                    } else {
                        ed_pchsAdptHhCnt.mandatory = "false";
                        ed_wrkWt.mandatory = "false";
                    }
                } else {
                    $c.gus.cfEnableBtnOnly([but_CalcPchsPcost]);
                    ed_pchsPcost.mandatory = "true";
                    lc_pchsAdjmStdCd.mandatory = "true";
                    ed_copCoClntNo.mandatory = "true";
                    ed_pchsClntNo.mandatory = "true";
                    if ("H" == pchsAdjmVal) {
                        ed_pchsAdptHhCnt.mandatory = "true";
                        ed_wrkWt.mandatory = "false";
                    } else if ("T" == pchsAdjmVal) {
                        ed_pchsAdptHhCnt.mandatory = "false";
                        ed_wrkWt.mandatory = "true";
                    } else {
                        ed_pchsAdptHhCnt.mandatory = "false";
                        ed_wrkWt.mandatory = "false";
                    }
                }
                $c.gus.cfDisableObjects([ed_pchsPcost]);
                $c.gus.cfRefreshMandSign();
            }
            if (ed_ctrlPchsPcost.getValue() > 0) {
                lc_ctrlPchsPcostRsn.mandatory = "true";
            } else {
                lc_ctrlPchsPcostRsn.mandatory = "false";
            }
            $c.gus.cfRefreshMandSign();
            break;

        case 5:
            if (ds_heavyEquipBasisInformation.getRowCount() > 0) {
                $c.gus.cfEnableBtnOnly([btn_InitDataCreate, btn_Save]);
            }
            if (ds_heavyEquipWorkResults.getRowCount() > 0) {
                $c.gus.cfEnableBtnOnly([btn_Save]);
                scwin.f_switchObjMode(4);
            }
            $c.gus.cfDisableObjects([ed_pchsPcost]);
            break;

        case 6:
            break;

        case 7:
            if (ds_heavyEquipWorkResults.getRowCount() == 0) {
                scwin.f_switchObjMode(1);
            } else {
                scwin.f_switchObjMode(4);
            }
            break;

        case 8:
            $c.gus.cfEnableKeyData();
            $c.gus.cfEnableObjects([btn_wrkIndictNo, ed_prtgCost, ed_pchsDeptCd]);
            $c.gus.cfDisableObjects([ed_pchsPcost]);
            scwin.f_OnWrkIndictClsCdChanged();
            break;
        default:
            break;
    }
    if (scwin.userClsCd != "01") {
        $c.gus.cfDisableObjects([ed_copCoClntNo, txt_copCoClntNm]);
    }
};

scwin.f_onFocusCall = function() {
    let pchsAdjmVal = lc_pchsAdjmStdCd.getValue();
    if (pchsAdjmVal == "H") {
        scwin.txt_check = ed_pchsAdptHhCnt.getValue();
    } else if (pchsAdjmVal == "T") {
        scwin.txt_check = ed_wrkWt.getValue();
    }
};

scwin.f_outFocusCall = function() {
    let pchsAdjmVal = lc_pchsAdjmStdCd.getValue();
    if (pchsAdjmVal == "H") {
        if (scwin.txt_check != ed_pchsAdptHhCnt.getValue()) {
            ed_pchsPcost.setValue(0);
            scwin.txt_check = "";
        }
    } else if (pchsAdjmVal == "T") {
        if (scwin.txt_check != ed_wrkWt.getValue()) {
            ed_pchsPcost.setValue(0);
            scwin.txt_check = "";
        }
    }
};

scwin.f_pchsAdjmStdCdOnFocusCall = function() {
    scwin.txt_check = lc_pchsAdjmStdCd.getValue();
};

scwin.f_pchsAdjmStdCdOutFocusCall = function() {
    if (lc_pchsAdjmStdCd.getValue() != scwin.txt_check) {
        ed_pchsPcost.setValue(0);
        scwin.txt_check = "";
    }

    let pchsAdjmVal = lc_pchsAdjmStdCd.getValue();
    if ("H" == pchsAdjmVal) {
        ed_pchsAdptHhCnt.mandatory = "true";
        ed_wrkWt.mandatory = "false";
    } else if ("T" == pchsAdjmVal) {
        ed_pchsAdptHhCnt.mandatory = "false";
        ed_wrkWt.mandatory = "true";
    }

    $c.gus.cfRefreshMandSign();
};

