scwin.gr_heavyEquipNonOperationHour_oneditend = async function(rowIndex, columnId, oldValue, newValue) {
    if (columnId != "nonoprtHhCnt" && columnId != "nonoprtMintCnt") return true;
    if (columnId == "nonoprtMintCnt") {
        if (ds_heavyEquipNonOperationHour.getCellData(rowIndex, columnId) >= 60) {
            ds_heavyEquipNonOperationHour.setCellData(rowIndex, columnId, 0);
            await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["비가동시간"]);
            return;
        }
    }
    if (ds_heavyEquipNonOperationHour.getCellData(rowIndex, "nonoprtHhCnt") > ed_totInputHhCnt.getValue()
     || (ds_heavyEquipNonOperationHour.getCellData(rowIndex, "nonoprtHhCnt") == ed_totInputHhCnt.getValue()
      && ds_heavyEquipNonOperationHour.getCellData(rowIndex, "nonoprtMintCnt") > ed_totInputMintCnt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["비가동시간", "총 투입시간"]);
        ds_heavyEquipNonOperationHour.setCellData(rowIndex, "nonoprtHhCnt", 0);
        ds_heavyEquipNonOperationHour.setCellData(rowIndex, "nonoprtMintCnt", 0);
        return;
    }

    scwin.f_CalcNonOperationHour();
    return true;
};
